import { isTauri } from '../platform';
import {
  isStringArray,
  storageGet,
  storageRemove,
  storageSet,
} from './storage';

const DB_PATH = 'sqlite:raycast_clone.db';

export interface ClipboardEntryRow {
  id: string;
  content: string;
  content_type: string;
  source_app: string;
  copied_at: string;
  pinned: number;
}

export interface SnippetRow {
  id: string;
  name: string;
