import { useCallback, useEffect, useMemo, useState } from 'react';
import { type ExtensionEntry, MOCK_EXTENSIONS } from '../../data/settings_data';
import { useAlert } from '../../hooks/use_alert';
import { useHUD } from '../../hooks/use_hud';
import { useKeyboardShortcut } from '../../hooks/use_keyboard_shortcut';
import { useNavigation } from '../../hooks/use_navigation';
import { useTheme } from '../../hooks/use_theme';
import { useWindow } from '../../hooks/use_window';
import { isRecord } from '../../utils/storage';
import { settingsDb } from '../../utils/database';
import { ActionPanel } from '../action_panel/action_panel';
import { CopyHUDIcon } from '../action_panel/actions';
import type { DropdownSection } from '../action_panel/actions_dropdown';
import { Alert } from '../alert/alert';
import { EmptyState } from '../empty_state/empty_state';
import { FormCheckbox } from '../form/form_checkbox';
import { FormDropdown } from '../form/form_dropdown';
import { FormSeparator } from '../form/form_separator';
import { HUDContainer } from '../hud/hud_container';
import { Kbd } from '../kbd/kbd';
import { SearchBar } from '../search_bar/search_bar';
import type { SearchDropdownSection } from '../search_bar/search_dropdown';
import { SearchDropdown } from '../search_bar/search_dropdown';
import './settings_view.scss';

type SettingsTab = 'general' | 'extensions' | 'advanced';

const SETTINGS_TABS: SettingsTab[] = [
  'general',
  'extensions',
  'advanced',
];

function isSettingsTab(value: string): value is SettingsTab {
  return SETTINGS_TABS.includes(value as SettingsTab);
}

interface GeneralSettings {
  appearance: string;
  windowPosition: string;
  windowWidth: string;
  showRecentApps: boolean;
  showDock: boolean;
  fontSize: string;
}

const SETTINGS_DB_KEY = 'settings-general';
const EXTENSIONS_DB_KEY = 'settings-extensions';

const DEFAULT_SETTINGS: GeneralSettings = {
  appearance: 'dark',
  windowPosition: 'top-third',
  windowWidth: 'medium',
  showRecentApps: true,
  showDock: true,
  fontSize: 'default',
};

function isGeneralSettings(value: unknown): value is GeneralSettings {
  if (!isRecord(value)) return false;
  return (
    typeof value.appearance === 'string' &&
    typeof value.windowWidth === 'string' &&
    typeof value.showRecentApps === 'boolean' &&
    typeof value.showDock === 'boolean' &&
    typeof value.fontSize === 'string' &&
    (value.windowPosition === undefined ||
      typeof value.windowPosition === 'string')
  );
}

function isBooleanRecord(value: unknown): value is Record<string, boolean> {
  if (!isRecord(value)) return false;
  return Object.values(value).every(v => typeof v === 'boolean');
}

function parseSettings(raw: string | null): GeneralSettings | null {
  if (!raw) return null;
  try {
    const parsed: unknown = JSON.parse(raw);
    return isGeneralSettings(parsed) ? parsed : null;
  } catch {
    return null;
  }
}

function parseExtensionStates(raw: string | null): Record<string, boolean> | null {
  if (!raw) return null;
  try {
    const parsed: unknown = JSON.parse(raw);
    return isBooleanRecord(parsed) ? parsed : null;
  } catch {
    return null;
  }
}

const TAB_SECTIONS: SearchDropdownSection[] = [
  {
    options: [
      {
        label: 'General',
        value: 'general',
      },
      {
        label: 'Extensions',
        value: 'extensions',
      },
      {
        label: 'Advanced',
        value: 'advanced',
      },
    ],
  },
];

const APPEARANCE_OPTIONS = [
  {
    label: 'Dark',
    value: 'dark',
  },
  {
    label: 'Light',
    value: 'light',
  },
  {
    label: 'System',
    value: 'system',
  },
];

const WINDOW_WIDTH_OPTIONS = [
  {
    label: 'Small (680px)',
    value: 'small',
  },
  {
    label: 'Medium (750px)',
    value: 'medium',
  },
  {
    label: 'Large (820px)',
    value: 'large',
  },
];

const WINDOW_POSITION_OPTIONS = [
  {
    label: 'Top Third',
    value: 'top-third',
  },
  {
    label: 'Center',
    value: 'center',
  },
];

const FONT_SIZE_OPTIONS = [
  {
    label: 'Small',
    value: 'small',
  },
  {
    label: 'Default',
    value: 'default',
  },
  {
    label: 'Large',
    value: 'large',
  },
];

function ToggleSwitch({
  checked,
  onChange,
  label,
}: {
  checked: boolean;
  onChange: (checked: boolean) => void;
  label: string;
}) {
  return (
    <label className="settings-toggle" onClick={e => e.stopPropagation()}>
      <input
        type="checkbox"
        className="settings-toggle__input"
        checked={checked}
        onChange={e => onChange(e.target.checked)}
        aria-label={label}
      />
      <div className="settings-toggle__track" />
      <div className="settings-toggle__knob" />
    </label>
  );
}

function ExportIcon() {
  return (
    <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
      <path
        d="M8 2v8M4.5 6L8 2l3.5 4"
        stroke="currentColor"
        strokeWidth="1.5"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
      <path
        d="M3 11v2.5h10V11"
        stroke="currentColor"
        strokeWidth="1.5"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  );
}

function ImportIcon() {
  return (
    <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
      <path
        d="M8 10V2M4.5 6L8 10l3.5-4"
        stroke="currentColor"
        strokeWidth="1.5"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
      <path
        d="M3 11v2.5h10V11"
        stroke="currentColor"
        strokeWidth="1.5"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  );
}

function TrashIconSmall() {
  return (
    <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
      <path
        d="M12 5v8.5a1 1 0 0 1-1 1H5a1 1 0 0 1-1-1V5M3 5h10M6.5 5V3.5a1 1 0 0 1 1-1h1a1 1 0 0 1 1 1V5"
        stroke="currentColor"
        strokeWidth="1.25"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  );
}

function SearchEmptyIcon() {
  return (
    <svg width="48" height="48" viewBox="0 0 48 48" fill="none">
      <circle cx="21" cy="21" r="12" stroke="currentColor" strokeWidth="3" />
      <line
        x1="30"
        y1="30"
        x2="42"
        y2="42"
        stroke="currentColor"
        strokeWidth="3"
        strokeLinecap="round"
      />
    </svg>
  );
}

function RefreshIconSmall() {
  return (
    <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
      <path
        d="M13 8A5 5 0 1 1 8 3h3"
        stroke="currentColor"
        strokeWidth="1.25"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
      <path
        d="M11 1l2 2-2 2"
        stroke="currentColor"
        strokeWidth="1.25"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  );
}

function GeneralTab({
  settings,
  onSettingsChange,
  onWindowPositionChange,
}: {
  settings: GeneralSettings;
  onSettingsChange: (settings: GeneralSettings) => void;
  onWindowPositionChange: (position: string) => void;
}) {
  return (
    <div className="form">
      <div className="form__fields">
        <FormDropdown
          label="Appearance"
          value={settings.appearance}
          onChange={v =>
            onSettingsChange({
              ...settings,
              appearance: v,
            })
          }
          options={APPEARANCE_OPTIONS}
        />
        <FormDropdown
          label="Window Position"
          value={settings.windowPosition}
          onChange={v => {
            onSettingsChange({
              ...settings,
              windowPosition: v,
            });
            onWindowPositionChange(v);
          }}
          options={WINDOW_POSITION_OPTIONS}
        />
        <FormDropdown
          label="Window Width"
          value={settings.windowWidth}
          onChange={v =>
            onSettingsChange({
              ...settings,
              windowWidth: v,
            })
          }
          options={WINDOW_WIDTH_OPTIONS}
        />
        <FormDropdown
          label="Font Size"
          value={settings.fontSize}
          onChange={v =>
            onSettingsChange({
              ...settings,
              fontSize: v,
            })
          }
          options={FONT_SIZE_OPTIONS}
        />
        <FormSeparator />
        <FormCheckbox
          label="Show Recent Applications"
          checked={settings.showRecentApps}
          onChange={v =>
            onSettingsChange({
              ...settings,
              showRecentApps: v,
            })
          }
          description="Display recently used apps in the root search"
        />
        <FormCheckbox
          label="Show Dock Apps"
          checked={settings.showDock}
          onChange={v =>
            onSettingsChange({
              ...settings,
              showDock: v,
            })
          }
          description="Include Dock applications in search results"
        />
        <FormSeparator />
        <div className="settings-hotkey">
          <span className="settings-hotkey__label">Raycast Hotkey</span>
          <Kbd
            keys={[
              '⌥',
              'Space',
            ]}
          />
