        </div>
        <div
          className="settings-action-row"
          onClick={onImport}
          role="button"
          tabIndex={0}
          onKeyDown={e => {
            if (e.key === 'Enter' || e.key === ' ') {
              e.preventDefault();
              onImport();
            }
          }}
        >
          <div className="settings-action-row__icon">
