import { recentCommandDb } from '../utils/database';

const MAX_RECENT = 10;

export function useRecentCommands() {
  const [recentIds, setRecentIds] = useState<string[]>([]);

  useEffect(() => {
    let cancelled = false;
    recentCommandDb
      .getAll(MAX_RECENT)
      .then(ids => {
        if (!cancelled) setRecentIds(ids);
      })
      .catch(console.error);
    return () => {
