      return next;
    });
    recentCommandDb.add(id).catch(console.error);
  }, []);

  const clearRecent = useCallback(() => {
    setRecentIds([]);
    recentCommandDb.clear().catch(console.error);
  }, []);

  return {
    recentIds,
    addRecent,
    clearRecent,
  };
}

